char *compile_program(char *source) {
    int prog;

    /* Initialize all subsystems */
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();
    mac_init();

    /* Build source line table for listing */
    src_lines_init(source, str_len(source));

    /* Parse */
    parse_init(source);
    prog = parse_program();
    if (parse_err) {
        return 0;
    }
    if (lex_fatal) {
        return 0;
    }

    /* Check for %DEFINE NOLISTING */
    if (def_defined("NOLISTING")) {
        cg_listing = 0;
    }

    /* Layout globals */
    layout_globals(prog);
    if (layout_err) {
        uart_putstr("STORAGE ERROR: ");
        uart_puts(layout_errmsg);
        return 0;
    }

    /* Emit runtime preamble (suppressed by %DEFINE LIBRARY) */
    if (!def_defined("LIBRARY")) {
        emit_runtime_start();
        emit_runtime_uart_putchar();
        emit_runtime_uart_getchar();
        emit_runtime_uart_puts();
    }

    /* Emit user procedures */
    cg_program_procs(prog);
    if (cg_err) {
        return 0;
    }

    /* Emit static data */
    cg_emit_static_data(prog);

    /* Emit string literal table */
    cg_emit_string_table();

    return emit_output();
}

void test_hello_world(void) {
    int errs;
    char *src;
    char *out;

    errs = 0;

    /* The hello world PL/SW source */
    src = "DCL MSG(20) CHAR INIT('Hello from PL/SW!');"
          "MAIN: PROC;"
          "  CALL UART_PUTS(ADDR(MSG));"
          "END;";

    uart_puts("--- compiling hello.plsw ---");
    out = compile_program(src);
    if (!out) {
        uart_puts("  FAIL: compilation failed");

